export const calculateDonationTotal = (donationString: string | undefined): number => {
    if (!donationString) return 0;
    
    let total = 0;
    const donations = donationString.split(',');
    
    for (const donation of donations) {
        const parts = donation.trim().split('@');
        if (parts.length === 2) {
            const amount = parseInt(parts[0]);
            if (!isNaN(amount)) {
                total += amount;
            }
        }
    }
    
    return total;
};
